import{_ as e,o as t,c as s,a0 as n}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"What is WakaWiki?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),i={name:"guide/getting-started.md"};function o(r,a,d,c,l,p){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="what-is-wakawiki" tabindex="-1">What is WakaWiki? <a class="header-anchor" href="#what-is-wakawiki" aria-label="Permalink to &quot;What is WakaWiki?&quot;">​</a></h1><p>WakaWiki is a CLI tool that uses LLMs to automatically generate and maintain structured documentation for any codebase. Inspired by <a href="https://github.com/langchain-ai/openwiki" target="_blank" rel="noreferrer">OpenWiki</a>, it acts as an agent that explores your source tree, reads files, searches for patterns, and writes documentation covering architecture, modules, and APIs.</p><h2 id="why-wakawiki" tabindex="-1">Why WakaWiki? <a class="header-anchor" href="#why-wakawiki" aria-label="Permalink to &quot;Why WakaWiki?&quot;">​</a></h2><p>Writing and maintaining documentation is tedious. WakaWiki delegates this to an LLM agent equipped with tools to navigate your codebase. The agent decides what to read, what to document, and where to write — all into a clean <code>wakawiki/</code> directory.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Explore</strong> — The agent lists files and directories to understand the project structure</li><li><strong>Read</strong> — Reads key source files to understand the code</li><li><strong>Search</strong> — Searches for patterns (functions, structs, traits) to find important code</li><li><strong>Write</strong> — Outputs well-structured Markdown docs into <code>wakawiki/</code></li><li><strong>Update</strong> — On subsequent runs, only refreshes changed files</li></ol><h2 id="output-structure" tabindex="-1">Output Structure <a class="header-anchor" href="#output-structure" aria-label="Permalink to &quot;Output Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>wakawiki/</span></span>
<span class="line"><span>├── index.md            # Project overview</span></span>
<span class="line"><span>├── architecture.md     # High-level architecture</span></span>
<span class="line"><span>├── modules/            # Per-module documentation</span></span>
<span class="line"><span>│   ├── main.md</span></span>
<span class="line"><span>│   ├── agent.md</span></span>
<span class="line"><span>│   └── ...</span></span>
<span class="line"><span>└── .wakawiki.json      # Metadata for incremental updates</span></span></code></pre></div><p>An <code>AGENTS.md</code> file is also created (or appended) with a reference block pointing coding agents to the <code>wakawiki/</code> directory.</p>`,9)])])}const k=e(i,[["render",o]]);export{h as __pageData,k as default};
